            const SizedBox(height: 8),
            Row(
              mainAxisAlignment: MainAxisAlignment.spaceEvenly,
              children: RpsChoice.values
                  .map((c) => _ChoiceButton(choice: c, onTap: () => _play(c)))
                  .toList(),
